mapper.select:
SELECT COUNT(*)
FROM INSTRUCTOR_FEATURED_COURSE
WHERE INSTR_UUID = #{instrUuid}

mapper.delete:
DELETE FROM INSTRUCTOR_FEATURED_COURSE
WHERE INSTR_UUID = #{instrUuid}
  AND COURSE_SN  = #{courseSn}

mapper.update:
UPDATE INSTRUCTOR_FEATURED_COURSE
SET DISPLAY_ORDER = #{displayOrder}
WHERE INSTR_UUID = #{instrUuid}
  AND COURSE_SN  = #{courseSn}
